const fs = require("fs");
const path = require("path");

module.exports = function (eleventyConfig) {

  // ─── Passthrough: existing landing page assets ──────────────────────────
  // NOTE: index.html is intentionally NOT in passthrough — Eleventy processes it
  //       as a Nunjucks template so the url filter can inject the correct base path.
  eleventyConfig.addPassthroughCopy("src/CNAME");
  eleventyConfig.addPassthroughCopy("src/assets");
  eleventyConfig.addPassthroughCopy("src/legal");
  eleventyConfig.addPassthroughCopy("src/auth");
  eleventyConfig.addPassthroughCopy("src/download");
  eleventyConfig.addPassthroughCopy("src/css");

  // ─── Collections (blog posts) ──────────────────────────────────────────────
  eleventyConfig.addCollection("postsEn", (api) =>
    api.getFilteredByGlob("src/posts/en/**/*.md").sort((a, b) => b.date - a.date)
  );


  // ─── Filters ────────────────────────────────────────────────────────────
  // Human-readable date:  "22 April 2026"
  eleventyConfig.addFilter("readableDate", (dateObj, locale = "en-GB") => {
    const d = dateObj instanceof Date ? dateObj : new Date(dateObj);
    return d.toLocaleDateString(locale, {
      day: "numeric",
      month: "long",
      year: "numeric",
    });
  });

  // ISO date string for <time datetime="…">
  eleventyConfig.addFilter("isoDate", (dateObj) => {
    const d = dateObj instanceof Date ? dateObj : new Date(dateObj);
    return d.toISOString().slice(0, 10);
  });

  // Returns the URL path to the article's hero image if it exists, or "" if not.
  // Convention: /assets/img/YYYY/MM/{slug}.png  (image file in src/assets/img/YYYY/MM/)
  eleventyConfig.addFilter("postImagePath", (dateObj, slug) => {
    const d = dateObj instanceof Date ? dateObj : new Date(dateObj);
    const year = d.getUTCFullYear();
    const month = String(d.getUTCMonth() + 1).padStart(2, "0");
    const relUrl = `/assets/img/${year}/${month}/${slug}.png`;
    const filePath = path.join(__dirname, "src", relUrl);
    return fs.existsSync(filePath) ? relUrl : "";
  });

  // Exclude a URL and return at most `limit` items — used for sidebars
  eleventyConfig.addFilter("excludeAndLimit", (posts, excludeUrl, limit = 5) => {
    return posts.filter((p) => p.url !== excludeUrl).slice(0, limit);
  });

  // Filter posts by a given tag value
  eleventyConfig.addFilter("filterByTag", (posts, tag) => {
    return posts.filter((p) => (p.data.postTags || []).includes(tag));
  });

  // ─── Tag list collections (unique tags per language, sorted A→Z) ────────
  const buildTagList = (posts) => {
    const counts = {};
    posts.forEach((p) => {
      (p.data.postTags || []).forEach((t) => { counts[t] = (counts[t] || 0) + 1; });
    });
    return Object.entries(counts)
      .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
      .map(([tag, count]) => ({ tag, count }));
  };

  // ─── Tag list collections ────────────────────────────────────────────────
  eleventyConfig.addCollection("tagListEn", (api) =>
    buildTagList(api.getFilteredByGlob("src/posts/en/**/*.md"))
  );

  // ─── Eleventy config ────────────────────────────────────────────────────
  return {
    templateFormats: ["njk", "md", "html"],
    markdownTemplateEngine: "njk",
    htmlTemplateEngine: "njk",
    pathPrefix: "/",
    dir: {
      input: "src",
      output: "_site",
      includes: "_includes",
      layouts: "_includes/layouts",
      data: "_data",
    },
  };
};

const fs = require("fs");
const path = require("path");

module.exports = function (eleventyConfig) {

  // ─── Passthrough: existing landing page assets ──────────────────────────
  // NOTE: index.html is intentionally NOT in passthrough — Eleventy processes it
  //       as a Nunjucks template so the url filter can inject the correct base path.
  eleventyConfig.addPassthroughCopy("src/CNAME");
  eleventyConfig.addPassthroughCopy("src/assets");
  eleventyConfig.addPassthroughCopy("src/legal");
  eleventyConfig.addPassthroughCopy("src/auth");
  eleventyConfig.addPassthroughCopy("src/download");
  eleventyConfig.addPassthroughCopy("src/css");

  // ─── Collections (blog posts) ──────────────────────────────────────────────
  eleventyConfig.addCollection("postsEn", (api) =>
    api.getFilteredByGlob("src/posts/en/**/*.md").sort((a, b) => b.date - a.date)
  );


  // ─── Filters ────────────────────────────────────────────────────────────
  // Human-readable date:  "22 April 2026"
  eleventyConfig.addFilter("readableDate", (dateObj, locale = "en-GB") => {
    const d = dateObj instanceof Date ? dateObj : new Date(dateObj);
    return d.toLocaleDateString(locale, {
      day: "numeric",
      month: "long",
      year: "numeric",
    });
  });

  // ISO date string for <time datetime="…">
  eleventyConfig.addFilter("isoDate", (dateObj) => {
    const d = dateObj instanceof Date ? dateObj : new Date(dateObj);
    return d.toISOString().slice(0, 10);
  });

  // Returns the URL path to the article's hero image if it exists, or "" if not.
  // Convention: /assets/img/YYYY/MM/{slug}.png|.webp  (image file in src/assets/img/YYYY/MM/)
  eleventyConfig.addFilter("postImagePath", (dateObj, slug) => {
    const d = dateObj instanceof Date ? dateObj : new Date(dateObj);
    const year = d.getUTCFullYear();
    const month = String(d.getUTCMonth() + 1).padStart(2, "0");
    for (const ext of ["png", "webp", "jpg", "jpeg"]) {
      const relUrl = `/assets/img/${year}/${month}/${slug}.${ext}`;
      const filePath = path.join(__dirname, "src", relUrl);
      if (fs.existsSync(filePath)) return relUrl;
    }
    return "";
  });

  // Exclude a URL and return at most `limit` items — used for sidebars
  eleventyConfig.addFilter("excludeAndLimit", (posts, excludeUrl, limit = 5) => {
    return posts.filter((p) => p.url !== excludeUrl).slice(0, limit);
  });

  // Filter posts by a given tag value
  eleventyConfig.addFilter("filterByTag", (posts, tag) => {
    return posts.filter((p) => (p.data.postTags || []).includes(tag));
  });

  // ─── Tag list collections (unique tags per language, sorted A→Z) ────────
  const buildTagList = (posts) => {
    const counts = {};
    posts.forEach((p) => {
      (p.data.postTags || []).forEach((t) => { counts[t] = (counts[t] || 0) + 1; });
    });
    return Object.entries(counts)
      .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
      .map(([tag, count]) => ({ tag, count }));
  };

  // ─── Tag list collections ────────────────────────────────────────────────
  eleventyConfig.addCollection("tagListEn", (api) =>
    buildTagList(api.getFilteredByGlob("src/posts/en/**/*.md"))
  );

  // ─── Eleventy config ────────────────────────────────────────────────────
  return {
    templateFormats: ["njk", "md", "html"],
    markdownTemplateEngine: "njk",
    htmlTemplateEngine: "njk",
    pathPrefix: "/",
    dir: {
      input: "src",
      output: "_site",
      includes: "_includes",
      layouts: "_includes/layouts",
      data: "_data",
    },
  };
};

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   Wishplace Blog — blog.css
   Simple, modern, clean. No frameworks.
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */

/* ── Tokens ──────────────────────────────── */
:root {
  --color-bg:         #ffffff;
  --color-surface:    #fafafa;
  --color-border:     #eaeaea;
  --color-text:       #000000;
  --color-muted:      #666666;
  --color-accent:     #000000;   /* sleek black — Wishplace brand */
  --color-accent-hover: #333333;
  --color-link:       #000000;

  --font-sans: "Inter", system-ui, -apple-system, sans-serif;
  --font-serif: Georgia, "Times New Roman", serif;

  --radius:    6px;
  --max-width: 700px;
  --max-width-wide: 960px;
}

/* ── Reset ───────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html {
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--font-sans);
  font-size: 1rem;
  line-height: 1.7;
  color: var(--color-text);
  background: var(--color-bg);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  overflow-wrap: break-word;
  word-wrap: break-word;
}

main { 
  flex: 1; 
  width: 100%;
}

a {
  color: var(--color-link);
  text-decoration: underline;
  text-underline-offset: 3px;
  transition: opacity 0.15s;
}
a:hover { opacity: 0.7; }

img { max-width: 100%; display: block; }

/* ── Header ──────────────────────────────── */
.site-header {
  border-bottom: 1px solid var(--color-border);
  background: var(--color-bg);
  position: sticky;
  top: 0;
  z-index: 100;
}

.header-inner {
  max-width: var(--max-width-wide);
  margin: 0 auto;
  padding: 0 1.5rem;
  min-height: 80px;            /* flexible instead of fixed height */
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
}

.brand {
  display: flex;
  align-items: center;
  text-decoration: none;
}
.brand-logo { 
  max-height: 120px;          /* was height: 120px — max-height lets both   */
  width: auto;                /* dimensions scale down proportionally when   */
  max-width: 100%;            /* the container is narrower than 600px        */
  display: block; 
}

.header-nav {
  display: flex;
  align-items: center;
  gap: 1.5rem;
  font-size: 0.9rem;
}
.header-lang-switcher {
  display: flex;
  gap: 0.5rem;
  align-items: center;
}
.header-lang-switcher a {
  text-decoration: none;
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--color-muted);
  transition: color 0.15s;
  padding: 0.2rem;
}
.header-lang-switcher a:hover {
  color: var(--color-text);
}
.header-lang-switcher a.active {
  color: var(--color-text);
  border-bottom: 2px solid var(--color-text);
}
.header-nav a { text-decoration: none; color: var(--color-muted); }
.header-nav a:hover { color: var(--color-text); }

.btn-cta {
  background: var(--color-accent) !important;
  color: #fff !important;
  padding: 0.4rem 0.9rem;
  border-radius: var(--radius);
  font-weight: 500;
  text-decoration: none !important;
  transition: background 0.15s;
}
.btn-cta:hover { background: var(--color-accent-hover) !important; }

/* ── Footer ──────────────────────────────── */
.site-footer {
  border-top: 1px solid var(--color-border);
  padding: 2rem 1.5rem;
  font-size: 0.85rem;
  color: var(--color-muted);
}
.footer-inner {
  max-width: var(--max-width-wide);
  margin: 0 auto;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: 0.75rem;
}
.footer-brand a { color: var(--color-muted); }
.footer-nav { display: flex; gap: 1.25rem; }
.footer-nav a { text-decoration: none; color: var(--color-muted); }
.footer-nav a:hover { color: var(--color-text); }
.footer-copy { color: var(--color-muted); }

/* ── Blog Home ───────────────────────────── */
.blog-home {
  max-width: var(--max-width-wide);
  margin: 0 auto;
  padding: 2.5rem 1.5rem;
}

.blog-home-hero {
  text-align: center;
  margin-bottom: 3.5rem;
}
.blog-home-hero h1 {
  font-size: clamp(2rem, 5vw, 3rem);
  font-weight: 600;
  letter-spacing: -0.03em;
  margin-bottom: 0.75rem;
}
.blog-home-tagline {
  font-size: 1.1rem;
  color: var(--color-muted);
  max-width: 520px;
  margin: 0 auto;
}

.lang-index-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 1.25rem;
}

.lang-card {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  padding: 1.75rem;
  border: 1px solid var(--color-border);
  border-radius: calc(var(--radius) * 2);
  text-decoration: none;
  color: var(--color-text);
  background: var(--color-surface);
  transition: border-color 0.15s, box-shadow 0.15s, transform 0.15s;
}
.lang-card:hover {
  border-color: var(--color-accent);
  box-shadow: 0 4px 16px rgba(0,0,0,0.07);
  transform: translateY(-2px);
  color: var(--color-text);
}
.lang-card-flag { font-size: 2rem; margin-bottom: 0.25rem; }
.lang-card-title { font-size: 1.2rem; font-weight: 600; }
.lang-card-desc { font-size: 0.9rem; color: var(--color-muted); flex: 1; }
.lang-card-cta {
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--color-accent);
  margin-top: 0.5rem;
}

/* ── Post List Page ──────────────────────── */
.post-list-page {
  max-width: var(--max-width-wide);
  margin: 0 auto;
  padding: 1.75rem 1.5rem 5rem;
  overflow: clip;              /* contain wide children without breaking sticky */
}

.post-list-header {
  margin-bottom: 3.5rem;
  display: flex;
  gap: 2rem;
  align-items: center;
  justify-content: space-between;
}
.post-list-header-content {
  flex: 1;
}

.post-list-hero-image {
  flex-shrink: 0;
  width: 140px;
  height: 140px;
  border-radius: 20%;
  overflow: hidden;
  box-shadow: 0 12px 24px rgba(0,0,0,0.06);
  border: 1px solid var(--color-border);
}
.post-list-hero-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

@media (max-width: 600px) {
  .post-list-header {
    flex-direction: column-reverse;
    align-items: flex-start;
    gap: 1.5rem;
    margin-bottom: 2.5rem;
  }
  .post-list-hero-image {
    width: 80px;
    height: 80px;
    border-radius: 16px;
  }
}

.breadcrumb-back {
  font-size: 0.85rem;
  color: var(--color-muted);
  text-decoration: none;
  display: inline-block;
  margin-bottom: 1rem;
}
.breadcrumb-back:hover { color: var(--color-accent); }

/* ── Split Layout (Featured + Sidebar) ─── */
.blog-split-layout {
  display: grid;
  /* minmax(0, Nfr) constrains each column's minimum to 0, so wide content
     (code blocks, images) cannot force a column—and thus the page—wider
     than the available viewport. */
  grid-template-columns: minmax(0, 3fr) minmax(0, 1fr);
  gap: 4rem;
  align-items: start;
  width: 100%;
}
/* Belt-and-suspenders: also set min-width on items themselves */
.blog-split-layout > * {
  min-width: 0;
}
.featured-post,
.sidebar-posts {
  min-width: 0;
  max-width: 100%;
  overflow: hidden;            /* hard clip – nothing inside can widen the page */
}
@media (max-width: 900px) {
  .blog-split-layout {
    display: flex;
    flex-direction: column;
    gap: 2.25rem;
  }

  .featured-post,
  .sidebar-posts {
    width: 100%;
    max-width: 100%;
  }
}

.featured-header {
  margin-bottom: 2rem;
  padding-bottom: 1.5rem;
  border-bottom: 1px solid var(--color-border);
}
.featured-header time {
  font-size: 0.85rem;
  color: var(--color-muted);
  display: block;
  margin-bottom: 0.75rem;
}
.featured-header h2 {
  font-size: 2rem;
  font-weight: 600;
  line-height: 1.25;
  letter-spacing: -0.03em;
}
.featured-header h2 a {
  color: var(--color-text);
  text-decoration: none;
}
.featured-header h2 a:hover {
  opacity: 0.7;
}

.sidebar-title {
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--color-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 1rem;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid var(--color-border);
}
.sidebar-posts .post-list { gap: 0; }
.sidebar-posts .post-card { padding: 1.25rem 0; }

.sidebar-all-link {
  display: inline-block;
  margin-top: 1rem;
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--color-text);
  text-decoration: none;
  border-bottom: 1px solid var(--color-text);
  padding-bottom: 1px;
  transition: opacity 0.15s;
}
.sidebar-all-link:hover { opacity: 0.6; }

/* ── Archive page ────────────────────────── */
.archive-header {
  margin-bottom: 2.5rem;
}
.archive-list {
  list-style: none;
  padding: 0;
}
.archive-item {
  display: grid;
  gap: 0.3rem;
  padding: 1.5rem 0;
  border-bottom: 1px solid var(--color-border);
}
.archive-item:first-child { border-top: 1px solid var(--color-border); }
.archive-title {
  font-size: 1.1rem;
  font-weight: 600;
  text-decoration: none;
  color: var(--color-text);
  line-height: 1.4;
}
.archive-title:hover { opacity: 0.7; }
.archive-desc {
  font-size: 0.9rem;
  color: var(--color-muted);
  line-height: 1.5;
  margin: 0;
}

.post-list-header h1 {
  font-size: clamp(2rem, 5vw, 3rem);
  font-weight: 600;
  letter-spacing: -0.04em;
  line-height: 1.1;
  display: flex;
  align-items: center;
  gap: 0.6rem;
  margin-bottom: 0.75rem;
}
.lang-label {
  display: inline-block;
  font-size: 0.7rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  background: var(--color-accent);
  color: #fff;
  padding: 0.2em 0.5em;
  border-radius: 4px;
  vertical-align: middle;
}
.post-list-tagline {
  margin-top: 0.5rem;
  color: var(--color-muted);
}

.post-list {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 0;
}

.post-card {
  padding: 1.5rem 0;
  border-bottom: 1px solid var(--color-border);
  display: grid;
  gap: 0.3rem;
}
.post-card:first-child { border-top: 1px solid var(--color-border); }

.post-card-date {
  font-size: 0.8rem;
  color: var(--color-muted);
  letter-spacing: 0.02em;
}
.post-card-title {
  font-size: 1.1rem;
  font-weight: 600;
  text-decoration: none;
  color: var(--color-text);
  line-height: 1.4;
}
.post-card-title:hover { color: var(--color-accent); }

.post-card-desc {
  font-size: 0.9rem;
  color: var(--color-muted);
  line-height: 1.5;
}

.post-card-langs {
  display: flex;
  gap: 0.4rem;
  margin-top: 0.25rem;
}
.lang-chip {
  font-size: 0.7rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  padding: 0.15em 0.45em;
  border: 1px solid var(--color-border);
  border-radius: 4px;
  text-decoration: none;
  color: var(--color-muted);
  transition: border-color 0.15s, color 0.15s;
}
.lang-chip:hover {
  border-color: var(--color-accent);
  color: var(--color-accent);
}

.post-list-empty { color: var(--color-muted); font-style: italic; padding: 1.5rem 0; }

/* ── Tags ────────────────────────────────── */
.tag-cloud {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
  margin-top: 0.5rem;
  max-width: 100%;
}
.tag-pill {
  display: inline-block;
  font-size: 0.72rem;
  font-weight: 500;
  letter-spacing: 0.03em;
  padding: 0.25em 0.65em;
  border: 1px solid var(--color-border);
  border-radius: 100px;
  text-decoration: none;
  color: var(--color-muted);
  background: var(--color-surface);
  transition: border-color 0.15s, color 0.15s, background 0.15s;
  white-space: nowrap;
  max-width: 100%;
}
.tag-pill:hover {
  border-color: var(--color-text);
  color: var(--color-text);
  background: var(--color-bg);
}
.tag-pill--lg {
  font-size: 0.9rem;
  padding: 0.3em 0.8em;
}
.sidebar-tags {
  margin-bottom: 0.25rem;
}
.article-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
  margin-top: 0.75rem;
  max-width: 100%;
}

.sidebar-posts a[href^="https://alessiodisalvo.it"] {
  overflow-wrap: anywhere;
  word-break: break-word;
}

/* ── Featured hero image ─────────────────── */
.featured-hero-image {
  width: 100%;
  max-width: 100%;
  aspect-ratio: 16 / 9;
  overflow: hidden;
  border-radius: calc(var(--radius) * 2);
  margin-bottom: 1.75rem;
  border: 1px solid var(--color-border);
}
.featured-hero-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* ── Article Lists ───────────────────────── */
.article-page {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 1.75rem 1.5rem 5rem;
  overflow: clip;
}

.article-header {
  margin-bottom: 2.5rem;
  padding-bottom: 1.5rem;
  border-bottom: 1px solid var(--color-border);
}

.article-meta {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  font-size: 0.82rem;
  color: var(--color-muted);
  margin-bottom: 1rem;
}

.article-lang-badge {
  display: inline-block;
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  background: var(--color-accent);
  color: #fff;
  padding: 0.2em 0.55em;
  border-radius: 4px;
}

.article-title {
  font-size: clamp(1.6rem, 4vw, 2.4rem);
  font-weight: 600;
  letter-spacing: -0.03em;
  line-height: 1.25;
  margin-bottom: 0.85rem;
}

.article-description {
  font-size: 1.1rem;
  color: var(--color-muted);
  line-height: 1.6;
  margin-bottom: 1rem;
}

/* Language switcher */
.lang-switcher {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex-wrap: wrap;
  font-size: 0.85rem;
  color: var(--color-muted);
  margin-top: 1rem;
}
.lang-link {
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  padding: 0.2em 0.55em;
  border: 1px solid var(--color-border);
  border-radius: 4px;
  text-decoration: none;
  color: var(--color-muted);
  transition: border-color 0.15s, color 0.15s;
}
.lang-link:hover {
  border-color: var(--color-accent);
  color: var(--color-accent);
}

/* ── Hero image ─────────────────────────── */
.article-hero {
  margin: 0 0 2.5rem;
  border-radius: 10px;
  overflow: hidden;
  line-height: 0;
}

.article-hero-img {
  width: 100%;
  max-height: 420px;
  object-fit: cover;
  display: block;
}

/* ── Prose (article body) ────────────────── */
.article-body {
  font-family: var(--font-serif);
  font-size: 1.05rem;
  line-height: 1.8;
  color: #2a2a2a;
  overflow: hidden;            /* contain wide code blocks / tables */
}

.article-body h2 {
  font-family: var(--font-sans);
  font-size: 1.35rem;
  font-weight: 600;
  letter-spacing: -0.02em;
  margin: 2.5rem 0 0.75rem;
  color: var(--color-text);
}

.article-body h3 {
  font-family: var(--font-sans);
  font-size: 1.1rem;
  font-weight: 600;
  margin: 1.75rem 0 0.5rem;
  color: var(--color-text);
}

.article-body p { margin-bottom: 1.4rem; }

.article-body a {
  color: var(--color-link);
  text-decoration: underline;
  text-decoration-thickness: 1px;
  text-underline-offset: 3px;
  transition: opacity 0.15s;
}
.article-body a:hover { opacity: 0.7; }

.article-body strong { font-weight: 600; color: var(--color-text); }

.article-body ol,
.article-body ul {
  padding-left: 1.5rem;
  margin-bottom: 1.4rem;
}
.article-body li { margin-bottom: 0.4rem; }

.article-body blockquote {
  border-left: 3px solid var(--color-accent);
  padding: 0.5rem 1.25rem;
  margin: 1.75rem 0;
  color: var(--color-muted);
  font-style: italic;
}

.article-body code {
  font-size: 0.88em;
  background: var(--color-surface);
  padding: 0.15em 0.4em;
  border-radius: 3px;
  font-family: "SF Mono", "Fira Code", monospace;
}

.article-body pre {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  padding: 1.25rem;
  display: block;
  width: 100%;
  overflow-x: auto;   /* horizontal scroll inside the block, not the page */
  max-width: 100%;    /* never wider than its grid column */
  margin-bottom: 1.4rem;
}
.article-body pre code { background: none; padding: 0; }

.article-body hr {
  border: none;
  border-top: 1px solid var(--color-border);
  margin: 2.5rem 0;
}

/* ── Article Footer ──────────────────────── */
.article-footer {
  margin-top: 3rem;
  padding-top: 1.5rem;
  border-top: 1px solid var(--color-border);
}
.back-link {
  font-size: 0.875rem;
  text-decoration: none;
  color: var(--color-muted);
}
.back-link:hover { color: var(--color-accent); }

/* ── Responsive ──────────────────────────── */
@media (max-width: 600px) {
  /* Header: shrink height and logo, preserve aspect ratio */
  .header-inner {
    height: auto;
    padding-top: 0.65rem;
    padding-bottom: 0.65rem;
    padding-left: 1rem;
    padding-right: 1rem;
  }
  .brand-logo {
    max-height: 52px; /* reduced from 120px — keeps correct proportions */
    width: auto;
    max-width: 100%;
  }
  .header-nav { gap: 1rem; }

  /* Give content meaningful side padding so text isn't edge-to-edge */
  .article-page,
  .post-list-page,
  .blog-home {
    padding-left: 1.25rem;
    padding-right: 1.25rem;
  }

  /* Force single-column grid on small screens */
  .lang-index-grid {
    grid-template-columns: minmax(0, 1fr);
  }

  .tag-pill {
    white-space: normal;
  }

  .footer-inner { flex-direction: column; align-items: flex-start; }
}

/* ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   Wishplace Blog — blog.css
   Simple, modern, clean. No frameworks.
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━ */

/* ── Tokens ──────────────────────────────── */
:root {
  --color-bg:         #ffffff;
  --color-surface:    #fafafa;
  --color-border:     #eaeaea;
  --color-text:       #000000;
  --color-muted:      #666666;
  --color-accent:     #000000;   /* sleek black — Wishplace brand */
  --color-accent-hover: #333333;
  --color-link:       #000000;

  --font-sans: "Inter", system-ui, -apple-system, sans-serif;
  --font-serif: Georgia, "Times New Roman", serif;

  --radius:    6px;
  --max-width: 700px;
  --max-width-wide: 960px;
}

/* ── Reset ───────────────────────────────── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

html {
  -webkit-text-size-adjust: 100%;
}

body {
  font-family: var(--font-sans);
  font-size: 1rem;
  line-height: 1.7;
  color: var(--color-text);
  background: var(--color-bg);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  overflow-wrap: break-word;
  word-wrap: break-word;
}

main { 
  flex: 1; 
  width: 100%;
}

a {
  color: var(--color-link);
  text-decoration: underline;
  text-underline-offset: 3px;
  transition: opacity 0.15s;
}
a:hover { opacity: 0.7; }

img { max-width: 100%; display: block; }

/* ── Header ──────────────────────────────── */
.site-header {
  border-bottom: 1px solid var(--color-border);
  background: var(--color-bg);
  position: sticky;
  top: 0;
  z-index: 100;
}

.header-inner {
  max-width: var(--max-width-wide);
  margin: 0 auto;
  padding: 0 1.5rem;
  min-height: 80px;            /* flexible instead of fixed height */
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
}

.brand {
  display: flex;
  align-items: center;
  text-decoration: none;
}
.brand-logo { 
  max-height: 120px;          /* was height: 120px — max-height lets both   */
  width: auto;                /* dimensions scale down proportionally when   */
  max-width: 100%;            /* the container is narrower than 600px        */
  display: block; 
}

.header-nav {
  display: flex;
  align-items: center;
  gap: 1.5rem;
  font-size: 0.9rem;
}
.header-lang-switcher {
  display: flex;
  gap: 0.5rem;
  align-items: center;
}
.header-lang-switcher a {
  text-decoration: none;
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--color-muted);
  transition: color 0.15s;
  padding: 0.2rem;
}
.header-lang-switcher a:hover {
  color: var(--color-text);
}
.header-lang-switcher a.active {
  color: var(--color-text);
  border-bottom: 2px solid var(--color-text);
}
.header-nav a { text-decoration: none; color: var(--color-muted); }
.header-nav a:hover { color: var(--color-text); }

.btn-cta {
  background: var(--color-accent) !important;
  color: #fff !important;
  padding: 0.4rem 0.9rem;
  border-radius: var(--radius);
  font-weight: 500;
  text-decoration: none !important;
  transition: background 0.15s;
}
.btn-cta:hover { background: var(--color-accent-hover) !important; }

/* ── Footer ──────────────────────────────── */
.site-footer {
  border-top: 1px solid var(--color-border);
  padding: 2rem 1.5rem;
  font-size: 0.85rem;
  color: var(--color-muted);
}
.footer-inner {
  max-width: var(--max-width-wide);
  margin: 0 auto;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: 0.75rem;
}
.footer-brand a { color: var(--color-muted); }
.footer-nav { display: flex; gap: 1.25rem; }
.footer-nav a { text-decoration: none; color: var(--color-muted); }
.footer-nav a:hover { color: var(--color-text); }
.footer-copy { color: var(--color-muted); }

/* ── Blog Home ───────────────────────────── */
.blog-home {
  max-width: var(--max-width-wide);
  margin: 0 auto;
  padding: 2.5rem 1.5rem;
}

.blog-home-hero {
  text-align: center;
  margin-bottom: 3.5rem;
}
.blog-home-hero h1 {
  font-size: clamp(2rem, 5vw, 3rem);
  font-weight: 600;
  letter-spacing: -0.03em;
  margin-bottom: 0.75rem;
}
.blog-home-tagline {
  font-size: 1.1rem;
  color: var(--color-muted);
  max-width: 520px;
  margin: 0 auto;
}

.lang-index-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 1.25rem;
}

.lang-card {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  padding: 1.75rem;
  border: 1px solid var(--color-border);
  border-radius: calc(var(--radius) * 2);
  text-decoration: none;
  color: var(--color-text);
  background: var(--color-surface);
  transition: border-color 0.15s, box-shadow 0.15s, transform 0.15s;
}
.lang-card:hover {
  border-color: var(--color-accent);
  box-shadow: 0 4px 16px rgba(0,0,0,0.07);
  transform: translateY(-2px);
  color: var(--color-text);
}
.lang-card-flag { font-size: 2rem; margin-bottom: 0.25rem; }
.lang-card-title { font-size: 1.2rem; font-weight: 600; }
.lang-card-desc { font-size: 0.9rem; color: var(--color-muted); flex: 1; }
.lang-card-cta {
  font-size: 0.9rem;
  font-weight: 500;
  color: var(--color-accent);
  margin-top: 0.5rem;
}

/* ── Post List Page ──────────────────────── */
.post-list-page {
  max-width: var(--max-width-wide);
  margin: 0 auto;
  padding: 1.75rem 1.5rem 5rem;
  overflow: clip;              /* contain wide children without breaking sticky */
}

.post-list-header {
  margin-bottom: 3.5rem;
  display: flex;
  gap: 2rem;
  align-items: center;
  justify-content: space-between;
}
.post-list-header-content {
  flex: 1;
}

.post-list-hero-image {
  flex-shrink: 0;
  width: 140px;
  height: 140px;
  border-radius: 20%;
  overflow: hidden;
  box-shadow: 0 12px 24px rgba(0,0,0,0.06);
  border: 1px solid var(--color-border);
}
.post-list-hero-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

@media (max-width: 600px) {
  .post-list-header {
    flex-direction: column-reverse;
    align-items: flex-start;
    gap: 1.5rem;
    margin-bottom: 2.5rem;
  }
  .post-list-hero-image {
    width: 80px;
    height: 80px;
    border-radius: 16px;
  }
}

.breadcrumb-back {
  font-size: 0.85rem;
  color: var(--color-muted);
  text-decoration: none;
  display: inline-block;
  margin-bottom: 1rem;
}
.breadcrumb-back:hover { color: var(--color-accent); }

/* ── Split Layout (Featured + Sidebar) ─── */
.blog-split-layout {
  display: grid;
  /* minmax(0, Nfr) constrains each column's minimum to 0, so wide content
     (code blocks, images) cannot force a column—and thus the page—wider
     than the available viewport. */
  grid-template-columns: minmax(0, 3fr) minmax(0, 1fr);
  gap: 4rem;
  align-items: start;
  width: 100%;
}
/* Belt-and-suspenders: also set min-width on items themselves */
.blog-split-layout > * {
  min-width: 0;
}
.featured-post,
.sidebar-posts {
  min-width: 0;
  max-width: 100%;
  overflow: hidden;            /* hard clip – nothing inside can widen the page */
}
@media (max-width: 900px) {
  .blog-split-layout {
    display: flex;
    flex-direction: column;
    gap: 2.25rem;
  }

  .featured-post,
  .sidebar-posts {
    width: 100%;
    max-width: 100%;
  }
}

.featured-header {
  margin-bottom: 2rem;
  padding-bottom: 1.5rem;
  border-bottom: 1px solid var(--color-border);
}
.featured-header time {
  font-size: 0.85rem;
  color: var(--color-muted);
  display: block;
  margin-bottom: 0.75rem;
}
.featured-header h2 {
  font-size: 2rem;
  font-weight: 600;
  line-height: 1.25;
  letter-spacing: -0.03em;
}
.featured-header h2 a {
  color: var(--color-text);
  text-decoration: none;
}
.featured-header h2 a:hover {
  opacity: 0.7;
}

.sidebar-title {
  font-size: 0.85rem;
  font-weight: 600;
  color: var(--color-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 1rem;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid var(--color-border);
}

/* ── About me block ──────────────────────── */
.about-me-block {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.75rem;
  margin-bottom: 2rem;
  text-align: center;
}
.about-me-photo {
  width: 96px;
  height: 96px;
  border-radius: 50%;
  display: block;
  object-fit: cover;
  margin: 0 auto 0.25rem;
}
.about-me-link {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--color-accent);
  text-decoration: underline;
}
.sidebar-posts .post-list { gap: 0; }
.sidebar-posts .post-card { padding: 1.25rem 0; }

.sidebar-all-link {
  display: inline-block;
  margin-top: 1rem;
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--color-text);
  text-decoration: none;
  border-bottom: 1px solid var(--color-text);
  padding-bottom: 1px;
  transition: opacity 0.15s;
}
.sidebar-all-link:hover { opacity: 0.6; }

/* ── Archive page ────────────────────────── */
.archive-header {
  margin-bottom: 2.5rem;
}
.archive-list {
  list-style: none;
  padding: 0;
}
.archive-item {
  display: flex;
  align-items: flex-start;
  gap: 1.25rem;
  padding: 1.5rem 0;
  border-bottom: 1px solid var(--color-border);
}
.archive-item:first-child { border-top: 1px solid var(--color-border); }
.archive-item-content {
  flex: 1;
  min-width: 0;
  display: grid;
  gap: 0.3rem;
}
.archive-item-thumb-link {
  flex-shrink: 0;
  display: block;
  align-self: center;
}
.archive-item-thumb {
  width: 110px;
  height: 78px;
  object-fit: cover;
  border-radius: 6px;
  display: block;
  transition: opacity 0.15s;
}
.archive-item-thumb:hover { opacity: 0.8; }
.archive-title {
  font-size: 1.1rem;
  font-weight: 600;
  text-decoration: none;
  color: var(--color-text);
  line-height: 1.4;
}
.archive-title:hover { opacity: 0.7; }
.archive-desc {
  font-size: 0.9rem;
  color: var(--color-muted);
  line-height: 1.5;
  margin: 0;
}

/* ── Pagination nav ──────────────────────── */
.pagination-nav {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  margin-top: 3rem;
  padding-top: 1.5rem;
  border-top: 1px solid var(--color-border);
  flex-wrap: wrap;
}
.pagination-pages {
  display: flex;
  list-style: none;
  padding: 0;
  margin: 0;
  gap: 0.35rem;
}
.pagination-btn,
.pagination-page {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 2.25rem;
  height: 2.25rem;
  padding: 0 0.6rem;
  border-radius: 6px;
  font-size: 0.875rem;
  font-weight: 500;
  text-decoration: none;
  transition: background 0.15s, color 0.15s;
  color: var(--color-text);
  border: 1px solid var(--color-border);
  background: transparent;
}
.pagination-btn:hover,
.pagination-page:hover {
  background: var(--color-accent);
  color: #fff;
  border-color: var(--color-accent);
}
.pagination-btn--disabled {
  opacity: 0.35;
  cursor: default;
  pointer-events: none;
}
.pagination-page--active {
  background: var(--color-accent);
  color: #fff;
  border-color: var(--color-accent);
  cursor: default;
}

.post-list-header h1 {
  font-size: clamp(2rem, 5vw, 3rem);
  font-weight: 600;
  letter-spacing: -0.04em;
  line-height: 1.1;
  display: flex;
  align-items: center;
  gap: 0.6rem;
  margin-bottom: 0.75rem;
}
.lang-label {
  display: inline-block;
  font-size: 0.7rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  background: var(--color-accent);
  color: #fff;
  padding: 0.2em 0.5em;
  border-radius: 4px;
  vertical-align: middle;
}
.post-list-tagline {
  margin-top: 0.5rem;
  color: var(--color-muted);
}

.post-list {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 0;
}

.post-card {
  padding: 1.5rem 0;
  border-bottom: 1px solid var(--color-border);
  display: grid;
  gap: 0.3rem;
}
.post-card:first-child { border-top: 1px solid var(--color-border); }
.post-card-content {
  display: grid;
  gap: 0.3rem;
}
.post-card-thumb-link {
  display: block;
  margin-bottom: 0.6rem;
}
.post-card-thumb {
  width: 100%;
  height: 140px;
  object-fit: cover;
  border-radius: 6px;
  display: block;
  transition: opacity 0.15s;
}
.post-card-thumb:hover { opacity: 0.8; }

.post-card-date {
  font-size: 0.8rem;
  color: var(--color-muted);
  letter-spacing: 0.02em;
}
.post-card-title {
  font-size: 1.1rem;
  font-weight: 600;
  text-decoration: none;
  color: var(--color-text);
  line-height: 1.4;
}
.post-card-title:hover { color: var(--color-accent); }

.post-card-desc {
  font-size: 0.9rem;
  color: var(--color-muted);
  line-height: 1.5;
}

.post-card-langs {
  display: flex;
  gap: 0.4rem;
  margin-top: 0.25rem;
}
.lang-chip {
  font-size: 0.7rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  padding: 0.15em 0.45em;
  border: 1px solid var(--color-border);
  border-radius: 4px;
  text-decoration: none;
  color: var(--color-muted);
  transition: border-color 0.15s, color 0.15s;
}
.lang-chip:hover {
  border-color: var(--color-accent);
  color: var(--color-accent);
}

.post-list-empty { color: var(--color-muted); font-style: italic; padding: 1.5rem 0; }

/* ── Tags ────────────────────────────────── */
.tag-cloud {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
  margin-top: 0.5rem;
  max-width: 100%;
}
.tag-pill {
  display: inline-block;
  font-size: 0.72rem;
  font-weight: 500;
  letter-spacing: 0.03em;
  padding: 0.25em 0.65em;
  border: 1px solid var(--color-border);
  border-radius: 100px;
  text-decoration: none;
  color: var(--color-muted);
  background: var(--color-surface);
  transition: border-color 0.15s, color 0.15s, background 0.15s;
  white-space: nowrap;
  max-width: 100%;
}
.tag-pill:hover {
  border-color: var(--color-text);
  color: var(--color-text);
  background: var(--color-bg);
}
.tag-pill--lg {
  font-size: 0.9rem;
  padding: 0.3em 0.8em;
}
.sidebar-tags {
  margin-bottom: 0.25rem;
}
.article-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
  margin-top: 0.75rem;
  max-width: 100%;
}

.sidebar-posts a[href^="https://alessiodisalvo.it"] {
  overflow-wrap: anywhere;
  word-break: break-word;
}

/* ── Featured hero image ─────────────────── */
.featured-hero-image {
  width: 100%;
  max-width: 100%;
  aspect-ratio: 16 / 9;
  overflow: hidden;
  border-radius: calc(var(--radius) * 2);
  margin-bottom: 1.75rem;
  border: 1px solid var(--color-border);
}
.featured-hero-image img {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

/* ── Article Lists ───────────────────────── */
.article-page {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 1.75rem 1.5rem 5rem;
  overflow: clip;
}

.article-header {
  margin-bottom: 2.5rem;
  padding-bottom: 1.5rem;
  border-bottom: 1px solid var(--color-border);
}

.article-meta {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  font-size: 0.82rem;
  color: var(--color-muted);
  margin-bottom: 1rem;
}

.article-lang-badge {
  display: inline-block;
  font-size: 0.68rem;
  font-weight: 700;
  letter-spacing: 0.08em;
  background: var(--color-accent);
  color: #fff;
  padding: 0.2em 0.55em;
  border-radius: 4px;
}

.article-title {
  font-size: clamp(1.6rem, 4vw, 2.4rem);
  font-weight: 600;
  letter-spacing: -0.03em;
  line-height: 1.25;
  margin-bottom: 0.85rem;
}

.article-description {
  font-size: 1.1rem;
  color: var(--color-muted);
  line-height: 1.6;
  margin-bottom: 1rem;
}

/* Language switcher */
.lang-switcher {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex-wrap: wrap;
  font-size: 0.85rem;
  color: var(--color-muted);
  margin-top: 1rem;
}
.lang-link {
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.05em;
  padding: 0.2em 0.55em;
  border: 1px solid var(--color-border);
  border-radius: 4px;
  text-decoration: none;
  color: var(--color-muted);
  transition: border-color 0.15s, color 0.15s;
}
.lang-link:hover {
  border-color: var(--color-accent);
  color: var(--color-accent);
}

/* ── Hero image ─────────────────────────── */
.article-hero {
  margin: 0 0 2.5rem;
  border-radius: 10px;
  overflow: hidden;
  line-height: 0;
}

.article-hero-img {
  width: 100%;
  height: auto;
  display: block;
}

/* ── Prose (article body) ────────────────── */
.article-body {
  font-family: var(--font-serif);
  font-size: 1.05rem;
  line-height: 1.8;
  color: #2a2a2a;
  overflow: hidden;            /* contain wide code blocks / tables */
}

.article-body h2 {
  font-family: var(--font-sans);
  font-size: 1.35rem;
  font-weight: 600;
  letter-spacing: -0.02em;
  margin: 2.5rem 0 0.75rem;
  color: var(--color-text);
}

.article-body h3 {
  font-family: var(--font-sans);
  font-size: 1.1rem;
  font-weight: 600;
  margin: 1.75rem 0 0.5rem;
  color: var(--color-text);
}

.article-body p { margin-bottom: 1.4rem; }

.article-body a {
  color: var(--color-link);
  text-decoration: underline;
  text-decoration-thickness: 1px;
  text-underline-offset: 3px;
  transition: opacity 0.15s;
}
.article-body a:hover { opacity: 0.7; }

.article-body strong { font-weight: 600; color: var(--color-text); }

.article-body ol,
.article-body ul {
  padding-left: 1.5rem;
  margin-bottom: 1.4rem;
}
.article-body li { margin-bottom: 0.4rem; }

.article-body blockquote {
  border-left: 3px solid var(--color-accent);
  padding: 0.5rem 1.25rem;
  margin: 1.75rem 0;
  color: var(--color-muted);
  font-style: italic;
}

.article-body code {
  font-size: 0.88em;
  background: var(--color-surface);
  padding: 0.15em 0.4em;
  border-radius: 3px;
  font-family: "SF Mono", "Fira Code", monospace;
}

.article-body pre {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  padding: 1.25rem;
  display: block;
  width: 100%;
  overflow-x: auto;   /* horizontal scroll inside the block, not the page */
  max-width: 100%;    /* never wider than its grid column */
  margin-bottom: 1.4rem;
}
.article-body pre code { background: none; padding: 0; }

.article-body hr {
  border: none;
  border-top: 1px solid var(--color-border);
  margin: 2.5rem 0;
}

/* ── Article Footer ──────────────────────── */
.article-footer {
  margin-top: 3rem;
  padding-top: 1.5rem;
  border-top: 1px solid var(--color-border);
}
.back-link {
  font-size: 0.875rem;
  text-decoration: none;
  color: var(--color-muted);
}
.back-link:hover { color: var(--color-accent); }

/* ── Responsive ──────────────────────────── */
@media (max-width: 600px) {
  /* Header: shrink height and logo, preserve aspect ratio */
  .header-inner {
    height: auto;
    padding-top: 0.65rem;
    padding-bottom: 0.65rem;
    padding-left: 1rem;
    padding-right: 1rem;
  }
  .brand-logo {
    max-height: 52px; /* reduced from 120px — keeps correct proportions */
    width: auto;
    max-width: 100%;
  }
  .header-nav { gap: 1rem; }

  /* Give content meaningful side padding so text isn't edge-to-edge */
  .article-page,
  .post-list-page,
  .blog-home {
    padding-left: 1.25rem;
    padding-right: 1.25rem;
  }

  /* Force single-column grid on small screens */
  .lang-index-grid {
    grid-template-columns: minmax(0, 1fr);
  }

  .tag-pill {
    white-space: normal;
  }

  .footer-inner { flex-direction: column; align-items: flex-start; }
}

---
layout: base.njk
title: All Articles
lang: en
description: Complete list of Mind Refactor articles.
pagination:
  data: collections.postsEn
  size: 12
  alias: paginatedPosts
permalink: "/en/articles/{% if pagination.pageNumber > 0 %}{{ pagination.pageNumber + 1 }}/{% endif %}index.html"
---

<section class="post-list-page">
  <header class="archive-header">
    <a href="{{ '/en/' | url }}" class="breadcrumb-back">← Back</a>
    <h1>All Articles <span class="lang-label">EN</span></h1>
  </header>

  <ol class="archive-list">
    {% for post in paginatedPosts %}
    {% set thumb = post.date | postImagePath(post.data.slug) %}
    <li class="archive-item{% if thumb %} has-thumb{% endif %}">
      <div class="archive-item-content">
        <time class="post-card-date" datetime="{{ post.date | isoDate }}">{{ post.date | readableDate("en-GB") }}</time>
        <a href="{{ post.url | url }}" class="archive-title">{{ post.data.title }}</a>

        {# ── Tags for archive item ── #}
        {% if post.data.postTags and post.data.postTags.length %}
        <div class="tag-cloud" style="margin-top: 0.25rem; margin-bottom: 0.25rem;">
          {% for t in post.data.postTags %}
          <a href="{{ ('/en/tags/' + t + '/') | url }}" class="tag-pill">{{ t }}</a>
          {% endfor %}
        </div>
        {% endif %}

        {% if post.data.description %}
        <p class="archive-desc">{{ post.data.description }}</p>
        {% endif %}
      </div>

      {% if thumb %}
      <a href="{{ post.url | url }}" class="archive-item-thumb-link" tabindex="-1" aria-hidden="true">
        <img src="{{ thumb | url }}" alt="{{ post.data.title }}" class="archive-item-thumb" />
      </a>
      {% endif %}
    </li>
    {% endfor %}
  </ol>

  {# ── Pagination nav ── #}
  {% if pagination.pages.length > 1 %}
  <nav class="pagination-nav" aria-label="Articles pagination">
    {% if pagination.href.previous %}
    <a href="{{ pagination.href.previous | url }}" class="pagination-btn" aria-label="Previous page">← Prev</a>
    {% else %}
    <span class="pagination-btn pagination-btn--disabled">← Prev</span>
    {% endif %}

    <ol class="pagination-pages">
      {% for pageUrl in pagination.hrefs %}
      <li>
        {% if loop.index0 == pagination.pageNumber %}
        <span class="pagination-page pagination-page--active" aria-current="page">{{ loop.index }}</span>
        {% else %}
        <a href="{{ pageUrl | url }}" class="pagination-page">{{ loop.index }}</a>
        {% endif %}
      </li>
      {% endfor %}
    </ol>

    {% if pagination.href.next %}
    <a href="{{ pagination.href.next | url }}" class="pagination-btn" aria-label="Next page">Next →</a>
    {% else %}
    <span class="pagination-btn pagination-btn--disabled">Next →</span>
    {% endif %}
  </nav>
  {% endif %}

</section>

---
layout: base.njk
title: Mind Refactor
lang: en
description: Product updates and essays on software, product thinking, and building in public.
permalink: /en/index.html
---
{% from "macros/tagcloud.njk" import tagCloud %}

<section class="post-list-page">

  {% set latestPost = collections.postsEn[0] %}

  {% if latestPost %}
  <div class="blog-split-layout">

    <article class="featured-post">
      <div class="featured-hero-image">
        <img src="{{ '/assets/img/mind-refactor-home.png' | url }}" alt="Exploring how technology reshapes our world" />
      </div>
      <header class="featured-header">
        <time datetime="{{ latestPost.date | isoDate }}">{{ latestPost.date | readableDate }}</time>
        <h2><a href="{{ latestPost.url | url }}">{{ latestPost.data.title }}</a></h2>

        {# ── Tags for featured post ── #}
        {% if latestPost.data.postTags and latestPost.data.postTags.length %}
        <div class="article-tags" style="margin-top: 0.5rem; margin-bottom: 1.5rem;">
          {% for t in latestPost.data.postTags %}
          <a href="{{ ('/en/tags/' + t + '/') | url }}" class="tag-pill">{{ t }}</a>
          {% endfor %}
        </div>
        {% endif %}
      </header>
      <div class="article-body">
        {{ latestPost.templateContent | safe }}
      </div>
    </article>

    <aside class="sidebar-posts">
      {{ tagCloud(collections.tagListEn, "en") }}

      <h3 class="sidebar-title" style="margin-top:1.75rem;">About me</h3>
      <div style="margin-bottom: 2rem;">
        <a href="https://alessiodisalvo.it" target="_blank" rel="noopener noreferrer" style="font-size: 0.85rem; font-weight: 500; color: var(--color-accent); text-decoration: underline;">Discover more about me on alessiodisalvo.it →</a>
      </div>

      <h3 class="sidebar-title">Recent articles</h3>
      <ol class="post-list" reversed>
        {% for post in collections.postsEn %}
          {% if loop.index0 > 0 and loop.index0 <= 5 %}
          <li class="post-card">
            <time class="post-card-date" datetime="{{ post.date | isoDate }}">
              {{ post.date | readableDate }}
            </time>
            <a href="{{ post.url | url }}" class="post-card-title">{{ post.data.title }}</a>

            {# ── Tags for post card ── #}
            {% if post.data.postTags and post.data.postTags.length %}
            <div class="tag-cloud" style="margin-top: 0.25rem; margin-bottom: 0.25rem;">
              {% for t in post.data.postTags %}
              <a href="{{ ('/en/tags/' + t + '/') | url }}" class="tag-pill">{{ t }}</a>
              {% endfor %}
            </div>
            {% endif %}

            {% if post.data.description %}
            <p class="post-card-desc">{{ post.data.description }}</p>
            {% endif %}
          </li>
          {% endif %}
        {% endfor %}
      </ol>
      <a href="{{ '/en/articles/' | url }}" class="sidebar-all-link">All articles →</a>
    </aside>

  </div>
  {% else %}
    <p class="post-list-empty">No articles yet — check back soon.</p>
  {% endif %}

</section>

---
layout: base.njk
title: Mind Refactor
lang: en
description: Product updates and essays on software, product thinking, and building in public.
permalink: /en/index.html
---
{% from "macros/tagcloud.njk" import tagCloud %}

<section class="post-list-page">

  {% set latestPost = collections.postsEn[0] %}

  {% if latestPost %}
  {% set featuredImage = latestPost.date | postImagePath(latestPost.data.slug) %}
  <div class="blog-split-layout">

    <article class="featured-post">
      <header class="featured-header">
        <time datetime="{{ latestPost.date | isoDate }}">{{ latestPost.date | readableDate }}</time>
        <h2><a href="{{ latestPost.url | url }}">{{ latestPost.data.title }}</a></h2>

        {# ── Tags for featured post ── #}
        {% if latestPost.data.postTags and latestPost.data.postTags.length %}
        <div class="article-tags" style="margin-top: 0.5rem; margin-bottom: 1.5rem;">
          {% for t in latestPost.data.postTags %}
          <a href="{{ ('/en/tags/' + t + '/') | url }}" class="tag-pill">{{ t }}</a>
          {% endfor %}
        </div>
        {% endif %}

        {# ── Featured image (after tags) ── #}
        <div class="featured-hero-image">
          <img
            src="{{ (featuredImage if featuredImage else '/assets/img/mind-refactor-home.png') | url }}"
            alt="{{ latestPost.data.title }}"
          />
        </div>
      </header>
      <div class="article-body">
        {{ latestPost.templateContent | safe }}
      </div>
    </article>

    <aside class="sidebar-posts">
      {{ tagCloud(collections.tagListEn, "en") }}

      <h3 class="sidebar-title" style="margin-top:1.75rem;">About me</h3>
      <div class="about-me-block">
        <img src="{{ '/assets/img/alessio-di-salvo.png' | url }}" alt="Alessio Di Salvo" class="about-me-photo" />
        <a href="https://alessiodisalvo.it" target="_blank" rel="noopener noreferrer" class="about-me-link">Discover more about me on alessiodisalvo.it</a>
      </div>

      <h3 class="sidebar-title">Recent articles</h3>
      <ol class="post-list" reversed>
        {% for post in collections.postsEn %}
          {% if loop.index0 > 0 and loop.index0 <= 5 %}
          {% set thumb = post.date | postImagePath(post.data.slug) %}
          <li class="post-card">
            {% if thumb %}
            <a href="{{ post.url | url }}" class="post-card-thumb-link" tabindex="-1" aria-hidden="true">
              <img src="{{ thumb | url }}" alt="{{ post.data.title }}" class="post-card-thumb" />
            </a>
            {% endif %}
            <div class="post-card-content">
              <time class="post-card-date" datetime="{{ post.date | isoDate }}">
                {{ post.date | readableDate }}
              </time>
              <a href="{{ post.url | url }}" class="post-card-title">{{ post.data.title }}</a>

              {# ── Tags for post card ── #}
              {% if post.data.postTags and post.data.postTags.length %}
              <div class="tag-cloud" style="margin-top: 0.25rem; margin-bottom: 0.25rem;">
                {% for t in post.data.postTags %}
                <a href="{{ ('/en/tags/' + t + '/') | url }}" class="tag-pill">{{ t }}</a>
                {% endfor %}
              </div>
              {% endif %}

              {% if post.data.description %}
              <p class="post-card-desc">{{ post.data.description }}</p>
              {% endif %}
            </div>
          </li>
          {% endif %}
        {% endfor %}
      </ol>
      <a href="{{ '/en/articles/' | url }}" class="sidebar-all-link">All articles →</a>
    </aside>

  </div>
  {% else %}
    <p class="post-list-empty">No articles yet — check back soon.</p>
  {% endif %}

</section>
